Update the workflow step below from actions/github-script@v8 conventions to the latest version. List the changes you made and why. Save the updated YAML to step.yml and the change notes to notes.md.

```yaml
- uses: actions/github-script@v8
  env:
    APP_TOKEN: ${{ secrets.APP_TOKEN }}
  with:
    script: |
      const { getOctokit } = require('@actions/github')
      const appOctokit = getOctokit(process.env.APP_TOKEN)
      await appOctokit.rest.repos.createDispatchEvent({
        owner: 'my-org',
        repo: 'service',
        event_type: 'deploy'
      })
```
